for item_index, item in enumerate(_input.all()):
  item_string = ''.join(item.json.data)
  string_array = [
     { 'data' : item_string[i:i+text_chunk_size]} 
    for i in range(0, len(item_string), text_chunk_size)

  ]

return string_array
